def validate_research_need(need):
    # N1: C-TOTALITY — need must be a dict
    if not isinstance(need, dict):
        return {"may_enter": False, "reason": "need must be a dict"}

    # N2: nec must be present and a dict
    if "nec" not in need or not isinstance(need["nec"], dict):
        return {"may_enter": False, "reason": "nec must be present and a dict"}

    nec = need["nec"]

    # N3: nec['validated'] must be exactly True (strict boolean check)
    if nec.get("validated") is not True:
        return {"may_enter": False, "reason": "nec['validated'] must be exactly True"}

    # N4: alternative_causes must be a non-empty list
    alt_causes = nec.get("alternative_causes")
    if not isinstance(alt_causes, list) or len(alt_causes) == 0:
        return {"may_enter": False, "reason": "nec['alternative_causes'] must be a non-empty list"}

    # N5: observed_block_refs must be a non-empty list
    obs_blocks = nec.get("observed_block_refs")
    if not isinstance(obs_blocks, list) or len(obs_blocks) == 0:
        return {"may_enter": False, "reason": "nec['observed_block_refs'] must be a non-empty list"}

    # N6: decision_to_support must be a non-empty string
    decision = need.get("decision_to_support")
    if not isinstance(decision, str) or len(decision) == 0:
        return {"may_enter": False, "reason": "decision_to_support must be a non-empty string"}

    # Semantic validation: ensure alternative_causes and observed_block_refs contain only valid string references
    # — each element must be a non-empty string (no None, no numbers, no dicts, no empty strings)
    for i, item in enumerate(alt_causes):
        if not isinstance(item, str) or len(item) == 0:
            return {"may_enter": False, "reason": f"nec['alternative_causes'][{i}] must be a non-empty string"}

    for i, item in enumerate(obs_blocks):
        if not isinstance(item, str) or len(item) == 0:
            return {"may_enter": False, "reason": f"nec['observed_block_refs'][{i}] must be a non-empty string"}

    # All checks passed
    return {"may_enter": True, "reason": "All validation rules satisfied"}
